"""
MKT Original Language Commentary — John chapters 9–10
Run: python3 scripts/zc-original-john-9-10.py

Source data used:
- data/interlinear/john.json (chapters 9–10 tokens)
- data/translation/glossary-greek.json (semantic ranges, dispute levels)
- data/translation/notes/john.json (translation reasoning)
- data/translation/draft/mediating/john.json (MKT text for reference)

Key decisions in this range:
- "the Evangelist" continues as authorial designation throughout
- ἐκ γενετῆς (9:1): "from birth" — the unusual preposition ἐκ underlines the
  absolute character of the condition (born *out of* this state)
- πηλός (9:6): mud/clay — connection to Gen 2:7 (divine formation) is noted
  without over-pressing it; it is a secondary register, not the main claim
- ἐπέχρισεν (9:6): "spread/anointed" — shares root with χρίω/Χριστός; noted
  as wordplay but not asserted as the Evangelist's primary intent
- ἀποσυνάγωγος (9:22): unique to John (9:22; 12:42; 16:2); translates the
  institutional act of synagogue expulsion
- δὸς δόξαν τῷ θεῷ (9:24): Jewish oath formula requiring truth-telling before
  God, not a request for praise — background from Josh 7:19
- κρίμα (9:39) vs κρίσις: the Evangelist uses κρίμα for the realized verdict;
  distinguished from the process-word κρίσις though the two often overlap in John
- καλός (10:11): "excellent/noble" — kalos carries aesthetic-ethical force
  that "good" in English misses; noted throughout
- παροιμία (10:6) vs παραβολή: the Evangelist's preferred term for figurative
  speech; not the synoptic parable form
- ἐξουσία (10:18): "authority" — delegated right, not mere capacity; appears
  twice (to lay down / to take up)
- ἕν (10:30): neuter "one thing/unity," not εἷς (masculine, one person) —
  the grammar preserves both unity and distinction
- ἡγίασεν (10:36): "set apart/sanctified" — same root as Ἐγκαίνια (v22);
  the Feast of Dedication frames the sanctification claim deliberately
- Ps 82:6 argument (10:34–36): qal wahomer from lesser to greater — noted as
  rabbinic-style argumentation; Jesus accepts the authority of the LXX text
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html


JOHN = {
  "9": {
    "1": '<p><strong>τυφλὸν ἐκ γενετῆς</strong> — "blind from birth." <em>Genet</em>ē (G1079) is the noun for birth itself; <em>ek genetēs</em> ("out of birth") marks the condition as coextensive with the man\'s entire existence, not an accident that came later. The Evangelist\'s terse opening — "as he went along, he saw a man blind from birth" — drops the reader into the scene without prologue, the blindness stated as a fixed, absolute fact.</p>',

    "2": '<p><strong>τίς ἥμαρτεν</strong> — "who sinned?" <em>Hamartanō</em> (G264, aorist). The disciples\' question assumes a theology of strict retributive correspondence: disability is the visible result of specific sin. This view circulated widely in Second Temple Judaism (cf. the rabbinic discussion in <em>b. Shabbat</em> 55a: "there is no death without sin, no suffering without transgression"). The question acknowledges two logical candidates — the man himself or his parents — but cannot conceive of a third option. Jesus will supply it.</p>',

    "3": '<p><strong>ἵνα φανερωθῇ τὰ ἔργα τοῦ θεοῦ ἐν αὐτῷ</strong> — purpose clause: "so that the works of God might be manifested in him." <em>Phaneroō</em> (G5319, aorist passive subjunctive) is one of the Evangelist\'s signature verbs for revelation made visible (cf. 1:31; 2:11; 3:21; 17:6). The clause does not explain the cause of the man\'s blindness from birth but the purpose of this encounter: the condition is now the site of divine display. <em>Ἐν αὐτῷ</em> — "in him" — the man himself is the locus of the manifestation, not merely its occasion.</p>',

    "4": '<p><strong>ἡμᾶς δεῖ ἐργάζεσθαι</strong> — "we must work." The manuscripts divide between <em>hēmas</em> ("we/us") and <em>eme</em> ("me/I"), with the plural having strong support. The <em>dei</em> (G1163) is the impersonal verb of divine necessity used repeatedly in John (3:7; 3:30; 4:4; 10:16; 20:9). <strong>ἔρχεται νύξ</strong> — "night is coming" — <em>nyx</em> here carries both literal and theological weight: the hours of Jesus\'s earthly mission are limited, and the darkness that is the condition of judgment (cf. 3:19–21) encroaches. The urgency of <em>works</em> follows from the finitude of the day.</p>',

    "5": '<p><strong>φῶς εἰμι τοῦ κόσμου</strong> — "I am the light of the world." The ἐγώ εἰμι formula with the predicate <em>phōs</em> (G5457) frames the healing about to occur: Jesus is about to give literal sight to one who is literally blind, enacting in physical form what he is claiming theologically. The <em>hotan</em> clause ("when I am in the world") marks this as the period of his incarnate presence — the light is embodied and located. Compare 8:12, where the same I-AM formula appears in the treasury of the temple.</p>',

    "6": '<p><strong>ἔπτυσεν χαμαί, ἐποίησεν πηλόν</strong> — "he spit on the ground, made mud." <em>Chamai</em> (G5476) means "on the ground" or "to the earth"; it appears only here and in 18:6 in the NT. The making of mud (<em>pēlos</em>, G4081) from saliva and earth carries a secondary register: in Gen 2:7, God forms (<em>eplassen</em>) man from the dust of the ground (<em>choûn apo tēs gēs</em>). The Evangelist does not invoke the parallel explicitly, but a healer who forms clay and restores sight to eyes is doing something that echoes the original act of creation. <strong>ἐπέχρισεν</strong> (G2025) — "he spread/anointed" — the verb shares its root with <em>chriō</em> (to anoint) and thus with <em>Christos</em>; the Anointed One anoints eyes that have never seen.</p>',

    "7": '<p><strong>Σιλωάμ ὃ ἑρμηνεύεται Ἀπεσταλμένος</strong> — "Siloam, which is translated Sent." The pool name derives from the Hebrew/Aramaic <em>Shiloaḥ</em> (שִׁילֹחַ), related to the verb <em>šālaḥ</em> (to send). The Evangelist\'s gloss (<em>hermēneuetai</em>) activates the central "sending" theology of the Fourth Gospel: Jesus is repeatedly identified as "the one sent" (<em>ho aposteillas me</em>, G649); the pool named "Sent" is where the man goes at the word of the Sent One. <strong>καὶ ἦλθεν βλέπων</strong> — "and came back seeing." The aorist <em>ēlthen</em> and the present participle <em>blepōn</em>: the coming is narrated as completed, the seeing as a present ongoing state.</p>',

    "8": '<p>A brief narrative transition. <strong>οἱ γείτονες</strong> (<em>hoi geitones</em>) — "the neighbors." The community who had previously seen him begging (<em>theōrountes</em>, present participle — a habitual sight to them) now face an identification problem. The imperfect <strong>ἦν</strong> + present participle <em>prosaitōn</em> ("was begging") frames his begging as a settled, ongoing condition — what had seemed permanent is now changed.</p>',

    "9": '<p><strong>ἐγώ εἰμι</strong> — "I am he." The man\'s self-identification uses the same formula with which Jesus discloses his divine identity throughout the Fourth Gospel (4:26; 6:20; 8:24, 28, 58; 18:5–6). Here the usage is entirely ordinary — the man is identifying himself, not making a theological claim. The juxtaposition is deliberate: the blind man who has just received sight from Jesus now speaks with the same words Jesus uses for himself. Both uses appear within a single chapter.</p>',

    "10": '<p>The neighbors\' question is direct: <strong>πῶς [οὖν] ἠνεῴχθησάν σου οἱ ὀφθαλμοί;</strong> — "how then were your eyes opened?" <em>Anoigō</em> (G455, aorist passive) — "opened." The passive voice asks who acted on his eyes without naming the actor. The question drives the three-stage interrogation that structures the rest of the chapter: neighbors (vv.8–12), Pharisees first round (vv.13–17), Pharisees with parents (vv.18–23), Pharisees second round (vv.24–34).</p>',

    "11": '<p><strong>ὁ ἄνθρωπος ὁ λεγόμενος Ἰησοῦς</strong> — "the man called Jesus." The healed man\'s first identification of Jesus is by name and title: "a man called Jesus." He does not yet know more. His account is precise and factual: mud on the eyes, the command to go to Siloam, washing, sight. <strong>ὑπῆγα</strong> (aorist, "I went") / <strong>ἐνιψάμην</strong> (aorist, "I washed") / <strong>ἀνέβλεψα</strong> (aorist, "I received sight") — three completed actions in sequence, the narration matching the simplicity of obedience.</p>',

    "12": '<p><strong>ποῦ ἐστιν ἐκεῖνος;</strong> — "Where is that man?" <em>Ekeinos</em> (G1565) in the Evangelist\'s usage often marks a figure whose significance is greater than the speaker realizes ("that one" — with Johannine depth). Here it is simply a demonstrative pointing to an absent party. The healed man\'s answer — "I don\'t know" (<em>ouk oida</em>) — marks the limit of his present knowledge and sets the stage for Jesus to seek him out at the chapter\'s end (v35).</p>',

    "13": '<p>Narrative transition: the healed man is brought (<em>agousin</em>, G71, present — they lead/bring him) to the Pharisees. The same word is used of leading a defendant to authorities; the framing subtly positions the healed man as someone summoned for examination rather than celebrated. The Pharisees are the ones who will determine whether the healing is legally permissible.</p>',

    "14": '<p><strong>ἦν δὲ σάββατον</strong> — "now it was a Sabbath." The Evangelist holds the Sabbath detail until after the healing is narrated, creating the same collision-effect as in 5:9: the miracle is complete, the controversy begins. The making of clay (<em>pēlon poiein</em>) was one of the thirty-nine categories of labor prohibited on the Sabbath (<em>Mishnah Shabbat</em> 7:2 lists kneading); the Pharisees will focus on this infraction rather than the restoration of sight.</p>',

    "15": '<p>The Pharisees\' direct question to the man — <strong>πῶς ἀνέβλεψας;</strong> — receives the same account he gave the neighbors, shortened: mud on eyes, washing, sight. <strong>πηλόν ἐπέθηκέν μου ἐπὶ τοὺς ὀφθαλμούς</strong> — "he put mud upon my eyes." The verb <em>epitithēmi</em> (G2007, to place upon) is clinical and specific — the man does not embellish. His testimony is consistent. The short retelling through the chapter (vv.7, 11, 15, 25) is a Johannine technique: each repetition before a new audience drives home both the simplicity and the finality of what happened.</p>',

    "16": '<p><strong>σχίσμα ἐν αὐτοῖς</strong> — "a division among them." <em>Schisma</em> (G4978) — "split/schism." This is the same word used in 7:43 and 10:19 for the divisions Jesus produces among listeners. The logic of the split is explicit: one party argues no one from God could break the Sabbath; the other asks how a sinner could perform such signs. <strong>ἁμαρτωλὸς</strong> (G268, "sinner") vs. <strong>ποιεῖν σημεῖα τοιαῦτα</strong> ("perform such signs") — the works testify against the sinner-verdict. The works-as-witness motif from chapter 5 is alive here.</p>',

    "17": '<p><strong>τί σὺ λέγεις περὶ αὐτοῦ</strong> — "what do you say about him?" The Pharisees turn the question to the man himself — a notable move. The healed man\'s answer is a step forward in his christological confession: <strong>προφήτης ἐστίν</strong> — "he is a prophet." From "a man called Jesus" (v11) to "a prophet" (v17). The progress will continue: at v25 he testifies to the undeniable; at v38 he worships. The chapter structures the blind man\'s confession as a journey from ignorance to full recognition.</p>',

    "18": '<p><strong>οὐκ ἐπίστευσαν</strong> — "did not believe." The aorist marks a decisive refusal, not ongoing uncertainty. <strong>ἕως ὅτου ἐφώνησαν τοὺς γονεῖς αὐτοῦ</strong> — "until they summoned his parents." The leaders cannot deny the healing; they shift to attacking the account by challenging the identity of the healed man. <em>Phōneō</em> (G5455, to call, summon) is used for authoritative summons — the parents are called as witnesses in a quasi-judicial process.</p>',

    "19": '<p>Three questions in sequence: Is this your son? Was he born blind? How does he now see? The tripartite structure is the formal structure of witness examination. <strong>ὃν ὑμεῖς λέγετε ὅτι τυφλὸς ἐγεννήθη</strong> — "whom you say was born blind." The leaders\' framing is skeptical: they attribute the claim of congenital blindness to the parents\' assertion, not yet accepting it as fact. The investigation is designed to find grounds for denial.</p>',

    "20": '<p><strong>οἴδαμεν ὅτι οὗτός ἐστιν ὁ υἱὸς ἡμῶν</strong> — "we know that this is our son." The first affirmation: identity confirmed. <strong>καὶ ὅτι τυφλὸς ἐγεννήθη</strong> — the second: congenital blindness confirmed. Both uses of <em>oida</em> (G1492, "we know") are emphatic; the parents affirm exactly what the authorities had cast in doubt. Their knowledge runs out at the third question.</p>',

    "21": '<p><strong>πῶς δὲ νῦν βλέπει οὐκ οἴδαμεν</strong> — "but how he now sees we do not know." The grammar is precise: they know the "what" (blindness, sight) but not the "how" (mechanism). <strong>αὐτὸς ἡλικίαν ἔχει</strong> — "he is of age" — <em>hēlikia</em> (G2244) means maturity, legal adulthood. The parents deflect to their son\'s legal competence to testify for himself — a calculated retreat that the Evangelist immediately explains in v22.</p>',

    "22": '<p><strong>ἀποσυνάγωγος</strong> (G656) — "put out of the synagogue." This compound (<em>apo-synagōgos</em>) appears only in the Fourth Gospel (9:22; 12:42; 16:2). Expulsion from the synagogue was a formal act of excommunication that cut the person from community worship, social belonging, and in some cases commercial life. <strong>ἤδη γὰρ συνετέθειντο οἱ Ἰουδαῖοι</strong> — "for the Jewish leaders had already agreed" — the perfect <em>syntetheninto</em> marks a settled, prior decision, not improvised reaction. The threat preceded this incident; the healed man\'s case now triggers the machinery.</p>',

    "23": '<p>A brief explanatory note: the parents\' evasion in v21 ("he is of age, ask him") is attributed entirely to this fear. <em>Dia touto</em> — "for this reason" — the evasion was not ignorance but calculated self-protection under threat of expulsion. The Evangelist does not condemn them; he explains their behavior as the understandable product of institutional pressure.</p>',

    "24": '<p><strong>δὸς δόξαν τῷ θεῷ</strong> — "Give glory to God." This is a formulaic oath-preamble in Jewish judicial and social settings, equivalent to "swear before God to tell the truth" (cf. Josh 7:19, where Joshua uses it to require Achan\'s confession; 1 Sam 6:5). It is not a call to praise God for the healing but a demand for truthful testimony under divine obligation. What follows — <strong>ἡμεῖς οἴδαμεν ὅτι οὗτος ὁ ἄνθρωπος ἁμαρτωλός ἐστιν</strong> — is the Pharisees\' predetermined conclusion, not an open question.</p>',

    "25": '<p><strong>εἰ ἁμαρτωλός ἐστιν οὐκ οἶδα· ἓν οἶδα</strong> — "whether he is a sinner I do not know; one thing I know." The structure is chiastic: acknowledged uncertainty followed by declared certainty. <strong>τυφλὸς ὢν ἄρτι βλέπω</strong> — "though I was blind, now I see." The participle <em>typhlos ōn</em> concedes the prior state; the present <em>blepō</em> asserts the present reality. This is testimony reduced to its irreducible minimum: what I was, what I am now. The Pharisees cannot dislodge this because they cannot argue against the man\'s own experience of himself.</p>',

    "26": '<p><strong>εἶπόν σοι ἤδη</strong> — "I told you already." The Evangelist records the escalating frustration on both sides: the Pharisees keep demanding the account; the healed man notes he has already given it. <strong>μήτι καὶ ὑμεῖς θέλετε αὐτοῦ μαθηταὶ γενέσθαι;</strong> (v27) — the counter-question, biting and ironic: "you don\'t also want to become his disciples, do you?" The <em>mēti</em> expects a negative answer but the framing exposes what is actually at stake in the investigation.</p>',

    "27": '<p><strong>εἶπόν ὑμῖν ἤδη καὶ οὐκ ἠκούσατε</strong> — "I told you already and you did not listen." <em>Ēkousate</em> (aorist, G191) — "you listened/heard." The verb implies not just acoustic reception but receptive attention. That they did not "hear" despite being told is the same diagnosis Jesus made of the religious leaders in chapters 5–8: they have ears but do not hear. <strong>μήτι καὶ ὑμεῖς θέλετε αὐτοῦ μαθηταὶ γενέσθαι;</strong> — the man\'s rhetoric has sharpened from factual testimony to pointed challenge, marking his growing confidence.</p>',

    "28": '<p><strong>σὺ μαθητὴς εἶ ἐκείνου, ἡμεῖς δὲ τοῦ Μωϋσέως ἐσμεν μαθηταί</strong> — "you are that man\'s disciple; we are disciples of Moses." The contrast is drawn in discipleship terms. <em>Ekeinou</em> ("of that one") is dismissive — they refuse to name Jesus. The self-identification with Moses is ironic in light of 5:45–47, where Jesus told these same leaders that Moses would be their accuser and that Moses wrote about him. The Mosaic credential they claim is the very thing that testifies against their rejection of Jesus.</p>',

    "29": '<p><strong>ἡμεῖς οἴδαμεν ὅτι Μωϋσεῖ λελάληκεν ὁ θεός</strong> — "we know that God has spoken to Moses." The perfect <em>lelālēken</em> marks an abiding fact: God\'s speech to Moses is completed and stands. <strong>τοῦτον δὲ οὐκ οἴδαμεν πόθεν ἐστίν</strong> — "but this man — we do not know where he is from." The Johannine irony reaches its peak: the reader knows exactly where Jesus is from (from above, from the Father, from God — cf. 7:27–29; 8:14). The leaders\' professed ignorance about his origin is the precise point at which they fail.</p>',

    "30": '<p><strong>ἐν τούτῳ γὰρ τὸ θαυμαστόν ἐστιν</strong> — "in this is the remarkable thing." <em>Thaumaston</em> (G2298) — "remarkable, marvelous, astonishing." The healed man\'s irony is sharp: they claim not to know where this man is from, yet he opened the eyes of one born blind — which, as v32 will note, has no precedent in recorded history. The man\'s argument is empirical: results this unprecedented require a source this extraordinary.</p>',

    "31": '<p><strong>οἴδαμεν ὅτι ἁμαρτωλῶν ὁ θεὸς οὐκ ἀκούει</strong> — "we know that God does not hear sinners." The man draws on common theological reasoning (cf. Ps 66:18; Prov 15:29): God\'s receptiveness to prayer is conditioned on the petitioner\'s moral standing. <strong>ἀλλ᾽ ἐάν τις θεοσεβὴς ᾖ καὶ τὸ θέλημα αὐτοῦ ποιῇ</strong> — "but if someone is devout toward God and does his will." The man\'s argument is a syllogism: God answers this man\'s acts; God does not hear sinners; therefore this man is not a sinner. The logic is the leaders\' own theology turned against their conclusion.</p>',

    "32": '<p><strong>ἐκ τοῦ αἰῶνος οὐκ ἠκούσθη</strong> — "from eternity it has not been heard." <em>Ek tou aiōnos</em> — "from the beginning of the age" — a hyperbolic claim of absolute uniqueness. That the eyes of a person born blind should be opened has no parallel in healing narratives the man can cite. The unprecedented nature of the sign is itself the argument for the unprecedented character of the one who performed it.</p>',

    "33": '<p><strong>εἰ μὴ ἦν οὗτος παρὰ θεοῦ, οὐκ ἠδύνατο ποιεῖν οὐδέν</strong> — "if this man were not from God, he could do nothing." The conditional (<em>ei mē ēn...ouk ēdynato</em>) is second-class (contrary to fact in form): the healed man is not raising a hypothesis but asserting a logical necessity. <em>Para theou</em> ("from God") — the same phrase the leaders denied (v16, "not from God"); the healed man asserts it as the only adequate explanation. The chapter\'s irony is complete: the man born blind sees clearly; those who see are blind (v39–41).</p>',

    "34": '<p><strong>ἐν ἁμαρτίαις σὺ ἐγεννήθης ὅλος</strong> — "in sins you were born wholly." The leaders deploy the retributive theology of v2 — which Jesus had explicitly rejected — as a weapon against the man who challenged them. <em>Holos</em> (G3650, "wholly/completely") is emphatic: the charge is total condemnation. <strong>ἐξέβαλον αὐτὸν ἔξω</strong> — "they cast him out." <em>Ekballō</em> (G1544, aorist) is the same verb used for casting out demons and for the expulsion Jesus warned about in v22. The man is formally expelled from the synagogue — the institutional consequence his parents feared has fallen on him instead.</p>',

    "35": '<p><strong>ἤκουσεν Ἰησοῦς ὅτι ἐξέβαλον αὐτὸν ἔξω</strong> — "Jesus heard that they had cast him out." The Evangelist uses <em>akouō</em> (G191, heard) — Jesus is informed. <strong>εὑρὼν αὐτόν</strong> — "having found him." The word <em>heuriskō</em> (G2147) — to find — carries the weight of the divine search here: the one expelled from human community is sought out by Jesus. The connection to Ezekiel 34 (the shepherd seeking the lost sheep) is active in the background. <strong>υἱὸν τοῦ ἀνθρώπου</strong> — the full Danielic title (G5207 + G444), unlike the anarthrous form in 5:27.</p>',

    "36": '<p><strong>τίς ἐστιν, κύριε, ἵνα πιστεύσω εἰς αὐτόν;</strong> — "Who is he, Lord, so that I may believe in him?" The man addresses Jesus with <em>kyrie</em> (G2962) — "Sir" or "Lord." The construction <em>hina pisteusō</em> (purpose clause, G4100, aorist subjunctive) indicates his readiness: he does not resist belief but lacks the object. The question mirrors the Samaritan woman\'s posture before Jesus\'s self-disclosure in 4:25–26.</p>',

    "37": '<p><strong>καὶ ἑώρακας αὐτόν, καὶ ὁ λαλῶν μετὰ σοῦ ἐκεῖνός ἐστιν</strong> — "you have both seen him, and the one speaking with you is he." The perfect <em>heōrakas</em> ("you have seen and the seeing stands") followed by the present <em>ho lalōn</em> ("the one speaking") — sight and speech converge in the same moment. Jesus identifies himself not with the divine <em>egō eimi</em> of 4:26 but with a gentle, direct pointing: "that one — he is the one speaking with you."</p>',

    "38": '<p><strong>κύριε, πιστεύω</strong> — "Lord, I believe." The transition from <em>kyrie</em> as polite address (v36) to <em>kyrie</em> as confession is complete in the act of <strong>προσεκύνησεν αὐτῷ</strong> — "he worshiped him." <em>Proskyneō</em> (G4352) is the verb used in John for worship of God (4:20–24; 12:20). The man born blind ends his day cast out of the synagogue and worshiping Jesus. The Evangelist does not need to comment: the progression from "a man called Jesus" (v11) → "a prophet" (v17) → "Lord" (v36) → worship (v38) speaks for itself.</p>',

    "39": '<p><strong>εἰς κρίμα ἐγὼ εἰς τὸν κόσμον τοῦτον ἦλθον</strong> — "for judgment I have come into this world." <em>Krima</em> (G2917) here is the realized verdict — the actual outcome of the process — rather than the juridical proceeding (<em>krisis</em>). The purpose clause that follows — "that those who do not see may see, and those who see may become blind" — expresses the inversion John 9 has dramatized: the blind man sees; the Pharisees, who claim to see, are exposed as blind. The judgment is not imposed externally; it is the sorting that occurs in the encounter with the light (cf. 3:19–21).</p>',

    "40": '<p>Some Pharisees who were with Jesus hear his pronouncement on blindness and take his statement as applying to themselves: <strong>μὴ καὶ ἡμεῖς τυφλοί ἐσμεν;</strong> — "Surely we are not blind too, are we?" The particle <em>mē</em> expects a negative answer — they are confident they are not blind. Their question reveals they heard Jesus\'s words but did not grasp that "those who see" and "those who are blind" are categories determined by response to the light, not by physical sight.</p>',

    "41": '<p><strong>εἰ τυφλοὶ ἦτε, οὐκ ἂν εἴχετε ἁμαρτίαν</strong> — "if you were blind, you would not have sin." The second-class condition (contrary-to-fact): their actual seeing is the problem, not blindness. Ignorance without opportunity for knowledge carries a different moral weight. <strong>νῦν δὲ λέγετε ὅτι βλέπομεν, ἡ ἁμαρτία ὑμῶν μένει</strong> — "but now you say \'we see,\' your sin remains." <em>Menei</em> (G3306, present, "abides/remains") — the Johannine verb of permanent dwelling applied to sin. Their claim to sight, combined with their refusal to see who Jesus is, constitutes their guilt and makes it permanent.</p>'
  },

  "10": {
    "1": '<p><strong>ὁ μὴ εἰσερχόμενος διὰ τῆς θύρας εἰς τὴν αὐλήν</strong> — "the one not entering through the gate into the sheep pen." <em>Aulē</em> (G833) — a courtyard or enclosure, not the sheep themselves (that is <em>poimnē</em>). The doubled amen-formula (<strong>ἀμὴν ἀμὴν</strong>) introduces the figure with the weight it carries throughout John (cf. 1:51; 3:3, 5, 11; 5:19, etc.). The scene is set at night, in a culture where sheep were gathered into a walled enclosure guarded by a single gate. The scenario is immediately legible to a Palestinian audience.</p>',

    "2": '<p><strong>ὁ δὲ εἰσερχόμενος διὰ τῆς θύρας ποιμήν ἐστιν τῶν προβάτων</strong> — "the one entering through the gate is the shepherd of the sheep." The contrast is absolute: the thief/robber climbs over; the shepherd enters by the gate. The legitimacy of the shepherd\'s access is visible in the method of entry. No comment is made yet about who the shepherd is; the figure is presented in terms of recognizable Palestinian shepherd practice before its allegorical key is given.</p>',

    "3": '<p><strong>τούτῳ ὁ θυρωρὸς ἀνοίγει</strong> — "to this one the gatekeeper opens." The gatekeeper (<em>thyrōros</em>, G2377) is a detail in the figure — he recognizes the legitimate shepherd and gives access. <strong>τὰ ἴδια πρόβατα φωνεῖ κατ᾽ ὄνομα</strong> — "he calls his own sheep by name." <em>Kat᾽ onoma</em> ("by name") signals individual, personal knowledge: not a collective summons but individual recognition. <strong>ἐξάγει αὐτά</strong> — present, ongoing leading out. The Eastern shepherd leads from the front, not driving from behind — a cultural detail that gives v4 its point.</p>',

    "4": '<p><strong>ἔμπροσθεν αὐτῶν πορεύεται</strong> — "he goes before them." The shepherd precedes the flock — he does not drive them. <strong>τὰ πρόβατα αὐτῷ ἀκολουθεῖ</strong> — "the sheep follow him." <em>Akoloutheō</em> (G190, to follow) is the technical Johannine word for discipleship. The reason for following is specified: <strong>ὅτι οἴδασιν τὴν φωνὴν αὐτοῦ</strong> — "because they know his voice." The basis of following is recognition, and the basis of recognition is knowing (perfect participle <em>oida</em>, G1492).</p>',

    "5": '<p><strong>ἀλλοτρίῳ δὲ οὐ μὴ ἀκολουθήσουσιν</strong> — "a stranger they will absolutely not follow." The double negative <em>ou mē</em> with the future indicative is the Greek idiom for the strongest possible denial. <em>Allotrios</em> (G245) — "belonging to another, foreign, alien" — the stranger is not merely unknown but categorically other. <strong>φεύξονται ἀπ᾽ αὐτοῦ</strong> — "they will flee from him." The sheep recognize the stranger\'s voice as not their shepherd\'s and respond with flight. The pastoral realism is exact: ancient shepherds had personal voices that their flocks recognized.</p>',

    "6": '<p><strong>ταύτην τὴν παροιμίαν</strong> — "this figure of speech." <em>Paroiimia</em> (G3942) — the Evangelist\'s term for figurative/proverbial speech — is distinct from the synoptic <em>parabolē</em>. While a parable typically presents a narrative scenario for comparison, <em>paroiimia</em> in John tends toward a riddle or enigmatic saying that conceals meaning from some and reveals it to others (cf. 16:25, 29). <strong>ἐκεῖνοι δὲ οὐκ ἔγνωσαν τίνα ἦν ἃ ἐλάλει αὐτοῖς</strong> — "but they did not know what it was he was saying to them." The failure to understand sets up the interpretive exposition that follows.</p>',

    "7": '<p><strong>ἐγώ εἰμι ἡ θύρα τῶν προβάτων</strong> — "I am the gate for the sheep." The I-AM formula with the predicate <em>thura</em> (G2374) — gate/door. In the figure, the gate was how legitimate shepherds entered; now Jesus identifies himself as the gate itself, through which both shepherds and sheep must pass. The claim shifts: Jesus is not only the shepherd (v11, 14) but also the sole point of legitimate access. The double amen-formula reintroduces the self-disclosure with the weight of a solemn declaration.</p>',

    "8": '<p><strong>πάντες ὅσοι ἦλθον πρὸ ἐμοῦ κλέπται εἰσὶν καὶ λῃσταί</strong> — "all who came before me are thieves and robbers." The statement is absolute but contextually bounded by the immediate discourse: "all who came before me" in the role of gate (i.e., those who claimed to be the sole legitimate access to God\'s people) are thieves and robbers. It is not a blanket dismissal of the OT prophets but a polemic against those who positioned themselves as gatekeepers of Israel and exploited the flock. <strong>οὐκ ἤκουσαν αὐτῶν τὰ πρόβατα</strong> — "the sheep did not listen to them" — the true sheep discerned the false shepherd.</p>',

    "9": '<p><strong>ἐγώ εἰμι ἡ θύρα</strong> — repeated I-AM: "I am the gate." The entry clause that follows is comprehensive: <strong>εἰσελεύσεται καὶ ἐξελεύσεται καὶ νομὴν εὑρήσει</strong> — "he will come in and go out and find pasture." Three future indicatives: entry (security in the enclosure), exit (freedom to move), and finding pasture (provision). <em>Nomē</em> (G3542) — pasture, the essential provision — appears only here and in 2 Tim 2:17 in the NT. Access through Jesus is not confinement but the combination of security and freedom.</p>',

    "10": '<p><strong>ὁ κλέπτης οὐκ ἔρχεται εἰ μὴ ἵνα κλέψῃ καὶ θύσῃ καὶ ἀπολέσῃ</strong> — "the thief comes only to steal and slaughter and destroy." Three aorist subjunctives in purpose clauses: the thief\'s entire agenda is defined by what he takes and destroys. <strong>ἐγὼ ἦλθον ἵνα ζωὴν ἔχωσιν καὶ περισσὸν ἔχωσιν</strong> — "I came that they may have life and have it abundantly." <em>Perissos</em> (G4053) — "excess, superabundance, overflowing measure." The contrast is total: the thief\'s purpose is pure subtraction; Jesus\'s is life beyond what sufficiency alone would provide.</p>',

    "11": '<p><strong>ἐγώ εἰμι ὁ ποιμὴν ὁ καλός</strong> — "I am the good shepherd." <em>Kalos</em> (G2570) — not merely "good" in a moral sense but "excellent, beautiful, noble" — the word carries both ethical and aesthetic force. The Greek phrase uses two definite articles (the shepherd, the excellent one) — this is a specific identity claim, not a generic description. <strong>τὴν ψυχὴν αὐτοῦ τίθησιν ὑπὲρ τῶν προβάτων</strong> — "lays down his life for the sheep." <em>Tithēmi</em> (G5087, present indicative — the laying down is his characteristic action) is deliberate: to place, to set down. Dying is here an act of will, not loss or defeat.</p>',

    "12": '<p><strong>ὁ μισθωτὸς</strong> (G3411) — "the hired hand." The contrast with the shepherd turns on ownership and stake: <strong>οὗ οὐκ ἔστιν τὰ πρόβατα ἴδια</strong> — "whose own the sheep are not." <em>Idia</em> (own, belonging to oneself) is the same word used in vv. 3–4 for the shepherd\'s own sheep. The hired hand has no personal investment in the flock. When the wolf comes (<em>erchetai ho lykos</em>, present — it comes as surely as it must), the hired hand abandons the sheep (<em>aphiēsin</em>, G863) and flees. The sheep are scattered (<em>diaskorpizei</em>, G4650 — "scattered/dispersed").</p>',

    "13": '<p><strong>ὅτι μισθωτός ἐστιν καὶ οὐ μέλει αὐτῷ περὶ τῶν προβάτων</strong> — "because he is a hired hand and does not care for the sheep." <em>Melei autō</em> (G3199) — "it matters to him, he cares." The negative <em>ou melei</em> — the sheep simply do not concern him at the level that would override self-preservation. The hired hand\'s flight is not cowardice; it is the logical consequence of his non-ownership. The lesson for leadership is blunt: those who serve for wages rather than vocation cannot be trusted in crisis.</p>',

    "14": '<p><strong>ἐγώ εἰμι ὁ ποιμὴν ὁ καλός, καὶ γινώσκω τὰ ἐμά</strong> — "I am the good shepherd, and I know my own." The I-AM formula is repeated (cf. v11) to anchor the mutual-knowing claim that follows. <em>Ginōskō</em> (G1097) here is not merely cognitive recognition but the relational, experiential knowing characteristic of covenant relationship — the same verb will be used in v15 for the Father-Son mutual knowledge.</p>',

    "15": '<p><strong>καθὼς γινώσκει με ὁ πατὴρ κἀγὼ γινώσκω τὸν πατέρα</strong> — "as the Father knows me, and I know the Father." The shepherd-sheep knowledge in v14 is grounded in the Father-Son knowledge in v15 — the same quality of relational knowledge (<em>ginōskō</em>) flows from the divine relationship into the shepherd\'s relationship with his flock. <strong>τὴν ψυχήν μου τίθημι ὑπὲρ τῶν προβάτων</strong> — repeated from v11 — the laying-down of life is the expression of this knowing-love, precisely as the Son gives himself in union with the Father\'s will.</p>',

    "16": '<p><strong>ἄλλα πρόβατα ἔχω ἃ οὐκ ἔστιν ἐκ τῆς αὐλῆς ταύτης</strong> — "I have other sheep that are not of this fold." <em>Aulē</em> (G833, enclosure/fold) — not <em>poimnē</em> (flock). The "other sheep" are outside the current enclosure (the Jewish community) but still the shepherd\'s own. The scope is Gentile inclusion. <strong>μίαν ποίμνην, εἷς ποιμήν</strong> — "one flock, one shepherd." The final state: a single <em>poimnē</em> (flock), not separate pens. The structural unity runs through a single shepherd, not through a single enclosure — mission, not ethnicity, defines belonging.</p>',

    "17": '<p><strong>διὰ τοῦτο ὁ πατήρ με ἀγαπᾷ ὅτι ἐγὼ τίθημι τὴν ψυχήν μου ἵνα πάλιν λάβω αὐτήν</strong> — "for this reason the Father loves me, because I lay down my life in order that I may take it up again." The Father\'s love (<em>agapā</em>, present — ongoing) is grounded in the Son\'s action of self-giving. Crucially, the purpose clause <em>hina palin labō</em> ("that I may take it up again") makes resurrection the built-in goal of the death itself — not an afterthought or reversal but the design of the laying-down.</p>',

    "18": '<p><strong>οὐδεὶς αἴρει αὐτὴν ἀπ᾽ ἐμοῦ, ἀλλ᾽ ἐγὼ τίθημι αὐτὴν ἀπ᾽ ἐμαυτοῦ</strong> — "no one takes it from me; I lay it down of my own accord." The agency is entirely the Son\'s: no one takes, he places. <strong>ἐξουσίαν ἔχω θεῖναι αὐτήν, καὶ ἐξουσίαν ἔχω πάλιν λαβεῖν αὐτήν</strong> — "I have authority to lay it down, and I have authority to take it up again." <em>Exousia</em> (G1849) — delegated right, authorized power — appears twice: once for death, once for resurrection. Both are acts of authority, not compulsion. <strong>ταύτην τὴν ἐντολὴν ἔλαβον παρὰ τοῦ πατρός μου</strong> — the authority is itself received from the Father: the Son\'s autonomy over death is a commissioned autonomy.</p>',

    "19": '<p><strong>σχίσμα πάλιν ἐγένετο ἐν τοῖς Ἰουδαίοις</strong> — "a division again arose among the Jews." <em>Schisma palin</em> — "division again" (G4978, G3825). The word <em>palin</em> links to 9:16, where the healing of the blind man produced the first <em>schisma</em>. The pattern is structural in John: Jesus\'s works and words sort listeners. <strong>διὰ τοὺς λόγους τούτους</strong> — specifically "because of these words" — the shepherd discourse is what divides them.</p>',

    "20": '<p><strong>δαιμόνιον ἔχει καὶ μαίνεται</strong> — "he has a demon and is raving." <em>Mainomai</em> (G3105, to be mad/raving) — the charge is that Jesus is demon-possessed and insane, and therefore not worth listening to. <em>Ti autou akouete</em> — "why do you listen to him?" The dismissal is total. That serious people disagree about whether Jesus is insane or not is itself a Johannine sign of division, not merely a note about audience reaction.</p>',

    "21": '<p><strong>ταῦτα τὰ ῥήματα οὐκ ἔστιν δαιμονιζομένου</strong> — "these words are not [the words] of a demon-possessed man." The counter-argument appeals to the quality of the teaching itself (<em>rhēmata</em> — spoken words/sayings). The second appeal reaches back to chapter 9: <strong>μὴ δαιμόνιον δύναται τυφλῶν ὀφθαλμοὺς ἀνοῖξαι;</strong> — "a demon cannot open the eyes of the blind, can it?" The healing stands as the test of the claim. The schism resolves into two fundamentally different readings of the evidence.</p>',

    "22": '<p><strong>Ἐγκαίνια</strong> (G1456) — "the Festival of Dedication." <em>Enkainia</em> from <em>kainos</em> (new) + the dedicatory prefix — it is the feast of the rededication of the Temple after Antiochus IV Epiphanes desecrated it in 168 BC, celebrated by the Maccabees in 165 BC (1 Macc 4:52–59; 2 Macc 10:1–8). Today this is Hanukkah. The thematic resonance is deliberate: at the feast commemorating the Temple\'s rededication, Jesus will describe himself as the one the Father has <em>sanctified</em> (<em>hēgiasen</em>, v36 — same root as <em>enkainia</em>). <strong>χειμὼν ἦν</strong> — "it was winter" — a detail fixing the calendar (late November/December) and perhaps underscoring the cold reception Jesus is about to receive.</p>',

    "23": '<p><strong>ἐν τῇ στοᾷ τοῦ Σολομῶνος</strong> — "in Solomon\'s Portico." This was the eastern colonnade of the Temple complex, known from Josephus (<em>Ant.</em> 20.9.7; <em>B.J.</em> 5.5.1–2) as a surviving structure from the Solomonic era or built to recall it. It provided shelter from wind in winter — which explains Jesus walking there in the cold month. The location will recur in Acts 3:11 and 5:12 as a gathering place for the early community.</p>',

    "24": '<p><strong>ἕως πότε τὴν ψυχὴν ἡμῶν αἴρεις;</strong> — "How long will you hold our souls in suspense?" The idiom <em>airō tēn psychēn</em> (G142 + G5590) means to keep someone in a state of suspense or anticipation — to lift the soul up in expectation without resolution (cf. LXX Ps 24:1; 85:4). The demand that follows — <strong>εἰ σὺ εἶ ὁ Χριστός, εἰπὲ ἡμῖν παρρησίᾳ</strong> — "if you are the Messiah, tell us plainly" — uses <em>parrēsia</em> (G3954, boldness/open speech). The request for plain speech is ironic: Jesus has been speaking plainly; they have not received it.</p>',

    "25": '<p><strong>εἶπον ὑμῖν καὶ οὐ πιστεύετε</strong> — "I told you and you do not believe." The verb tenses are precise: <em>eipon</em> (aorist, I told — a completed past act) vs. <em>pisteuete</em> (present, you do not believe — an ongoing state). The problem is not lack of information but lack of receptivity. <strong>τὰ ἔργα ἃ ἐγὼ ποιῶ ἐν τῷ ὀνόματι τοῦ πατρός μου, ταῦτα μαρτυρεῖ περὶ ἐμοῦ</strong> — "the works I do in my Father\'s name, these testify about me." The works-as-witness motif from 5:36 reappears: Jesus appeals not to claims but to deeds, which are the Father\'s testimony.</p>',

    "26": '<p><strong>ἀλλὰ ὑμεῖς οὐ πιστεύετε, ὅτι οὐκ ἐστὲ ἐκ τῶν προβάτων τῶν ἐμῶν</strong> — "but you do not believe, because you are not of my sheep." The causal relation here is striking: they do not believe because they are not his sheep — not: they are not his sheep because they do not believe. Their unbelief is diagnostic, not constitutive. The sheep-belonging precedes and explains the believing, in the same way that the Father\'s giving precedes the coming to Jesus in 6:37–44.</p>',

    "27": '<p><strong>τὰ πρόβατά μου τῆς φωνῆς μου ἀκούουσιν</strong> — "my sheep hear my voice." All three verbs are present indicative: <em>akouousin</em> (hear), <em>ginōskō</em> (I know), <em>akolouthiousin</em> (they follow). The present tense marks the ongoing, characteristic relationship between shepherd and sheep — not a one-time event but the habitual pattern. The hearing-knowing-following triad is the complete description of what discipleship looks like from the shepherd\'s perspective.</p>',

    "28": '<p><strong>κἀγὼ ζωὴν αἰώνιον δίδωμι αὐτοῖς, καὶ οὐ μὴ ἀπόλωνται εἰς τὸν αἰῶνα</strong> — "and I give them eternal life, and they will never perish forever." <em>Ou mē</em> with the aorist subjunctive — the strongest Greek negative: absolutely not at any point. <em>Eis ton aiōna</em> ("for the age/forever") reinforces the temporal absoluteness. <strong>καὶ οὐχ ἁρπάσει τις αὐτὰ ἐκ τῆς χειρός μου</strong> — "no one will snatch them from my hand." <em>Harpazō</em> (G726, to seize by force, snatch) — the word used for violent taking. The security is not the sheep\'s grip on the shepherd but the shepherd\'s grip on them.</p>',

    "29": '<p><strong>ὁ πατήρ μου ὃ δέδωκέν μοι πάντων μεῖζόν ἐστιν</strong> — "my Father, who has given them to me, is greater than all." The perfect <em>dedōken</em> ("has given and the giving stands") marks the Father\'s gift of the sheep as a completed, permanent delegation. <strong>καὶ οὐδεὶς δύναται ἁρπάζειν ἐκ τῆς χειρὸς τοῦ πατρός</strong> — "and no one is able to snatch from the Father\'s hand." Two hands hold the sheep: the Son\'s (v28) and the Father\'s (v29). The double security is grounded in the Father\'s superior greatness — nothing surpasses the Father\'s power, therefore nothing can overcome his hold.</p>',

    "30": '<p><strong>ἐγὼ καὶ ὁ πατὴρ ἕν ἐσμεν</strong> — "I and the Father are one." The word order places the two subjects before the verb. <em>Hen</em> is neuter (one thing, one unity) — not <em>heis</em> (masculine, one person). The grammar of this sentence preserves both the reality of unity (one) and the reality of distinction (I and the Father — two subjects, plural verb <em>esmen</em>). The statement is not modalism (the Father and Son are the same person) but the assertion of a unity of will, purpose, action, and nature that the leaders immediately interpret as a claim to divinity (v33: "you, being a man, make yourself God").</p>',

    "31": '<p><strong>ἐβάστασαν πάλιν λίθους</strong> — "they picked up stones again." <em>Palin</em> — "again" — referring back to 8:59. The act of stone-picking is immediate and wordless; the leaders understand the claim of v30 without needing further clarification. The use of <em>bastazō</em> (G941, to carry/bear) rather than a simple "they took up" suggests the weight and deliberateness of the act: they equipped themselves for execution.</p>',

    "32": '<p><strong>πολλὰ ἔργα καλὰ ἔδειξα ὑμῖν ἐκ τοῦ πατρός</strong> — "I have shown you many good works from the Father." <em>Kalos</em> again — the word from v11 applied to the shepherd. <strong>διὰ ποῖον αὐτῶν ἔργον ἐμὲ λιθάζετε;</strong> — "for which of them are you stoning me?" The question forces the leaders to name their actual objection. Their answer in v33 is precise: not for any work, but for the claim about himself.</p>',

    "33": '<p><strong>περὶ βλασφημίας, καὶ ὅτι σύ, ἄνθρωπος ὤν, ποιεῖς σεαυτὸν θεόν</strong> — "for blasphemy, because you, being a man, make yourself God." The charge of blasphemy (G988) in Jewish law applied to those who usurped divine honor or misused the divine name. The leaders\' framing is exact: they understand the claim of v30 as a man claiming to be God (<em>theon</em>, anarthrous — they may mean "a god" or "divine"), not merely a divine agent. Whether they heard v30 as an ontological identity claim or as an improper self-elevation, the charge is precise and the stoning response is legally consistent with Lev 24:16.</p>',

    "34": '<p><strong>οὐκ ἔστιν γεγραμμένον ἐν τῷ νόμῳ ὑμῶν, Ἐγώ εἶπα θεοί ἐστε;</strong> — "Is it not written in your law: I have said you are gods?" Jesus quotes the LXX of Psalm 82:6 (<em>egō eipa theoi este</em>). <strong>ἐν τῷ νόμῳ ὑμῶν</strong> — "in your law" — "your" is not dismissive (Jesus uses "the law" in the same way elsewhere) but addresses his opponents using their own highest authority against them. The "law" here includes the Psalms, as was common Jewish usage (cf. 12:34; 15:25).</p>',

    "35": '<p><strong>εἰ ἐκείνους εἶπεν θεούς, πρὸς οὓς ὁ λόγος τοῦ θεοῦ ἐγένετο</strong> — "if he called those gods, to whom the word of God came." The argument is a <em>qal wahomer</em> (from the lesser to the greater): if Scripture can apply the term <em>theos</em> to human judges or rulers who received God\'s word, it cannot be blasphemy for the one who is the eternal Word to bear the title. <strong>καὶ οὐ δύναται λυθῆναι ἡ γραφή</strong> — "and Scripture cannot be broken." <em>Lyō</em> (G3089, to loosen, annul, dissolve) — Jesus\'s hermeneutical axiom: the Scripture holds. Its words, once written, carry binding force.</p>',

    "36": '<p><strong>ὃν ὁ πατὴρ ἡγίασεν καὶ ἀπέστειλεν εἰς τὸν κόσμον</strong> — "whom the Father sanctified and sent into the world." <em>Hagiazō</em> (G37, aorist — a completed act of setting apart) resonates with the festival context of Hanukkah (<em>Enkainia</em>, v22 — rededication/sanctification). At the feast of the Temple\'s rededication, Jesus identifies himself as the one the Father truly set apart. The two aorists run in sequence: the Father first sanctified (<em>hēgiasen</em>), then sent (<em>apesteilen</em>). The sending flows from the sanctification. <strong>ὅτι εἶπον, Υἱὸς τοῦ θεοῦ εἰμι</strong> — "because I said, I am the Son of God" — the precise claim at issue.</p>',

    "37": '<p><strong>εἰ οὐ ποιῶ τὰ ἔργα τοῦ πατρός μου, μὴ πιστεύετέ μοι</strong> — "if I do not do the works of my Father, do not believe me." The conditional makes the works the test: the claim to Sonship must be validated by the works. The works are the Father\'s own works performed through the Son — the origin of the works is the criterion.</p>',

    "38": '<p><strong>εἰ δὲ ποιῶ, κἂν ἐμοὶ μὴ πιστεύητε, τοῖς ἔργοις πιστεύετε</strong> — "but if I do, even if you do not believe me, believe the works." This is an appeal stripped to its minimal form: if personal trust in Jesus is beyond them, the works themselves stand as evidence. The purpose clause that follows: <strong>ἵνα γνῶτε καὶ γινώσκητε</strong> — "that you may know and keep knowing." The aorist <em>gnōte</em> (come to know, initial knowledge) + present subjunctive <em>ginōskete</em> (ongoing understanding) combine: the works are meant to trigger a moment of recognition that develops into sustained understanding.</p>',

    "39": '<p><strong>ἐζήτουν οὖν αὐτὸν πάλιν πιάσαι</strong> — "again they tried to seize him." <em>Piazō</em> (G4084) — to seize, arrest. The imperfect <em>ezētoun</em> ("kept seeking") marks ongoing, unsuccessful attempts. <strong>καὶ ἐξῆλθεν ἐκ τῆς χειρὸς αὐτῶν</strong> — "and he escaped their grasp." Literally, "went out from their hand." The same word for hand (<em>cheir</em>) used in vv. 28–29 of the Father\'s and Son\'s protective hands holding the sheep: no one can snatch the sheep from those hands; the one whose hands those are passes through the opponents\' hands unharmed.</p>',

    "40": '<p><strong>ὅπου ἦν Ἰωάννης τὸ πρῶτον βαπτίζων</strong> — "where John had been baptizing at first." The withdrawal to Transjordan is a return to beginnings: the place where John\'s ministry started (1:28, Bethany beyond the Jordan). Jesus removes himself from the Temple precincts where the confrontation has reached impasse. <strong>ἔμεινεν ἐκεῖ</strong> — "he stayed there" — <em>menō</em> (G3306), the Evangelist\'s verb of purposeful dwelling. The stay is not flight but relocation to fruitful ground.</p>',

    "41": '<p><strong>Ἰωάννης μὲν σημεῖον ἐποίησεν οὐδέν</strong> — "John indeed performed no sign." The contrast is explicit: John the Baptist was a truthful witness but not a miracle-worker. His prophetic function was testimony, not demonstration. <strong>πάντα δὲ ὅσα εἶπεν Ἰωάννης περὶ τούτου ἀληθῆ ἦν</strong> — "but all that John said about this man was true." <em>Alēthē ēn</em> — past tense, as if summarizing a completed record: John\'s entire testimony has been vindicated. <em>Toutos</em> ("this one") — the same demonstrative the Jewish leaders used dismissively (9:29: <em>toutou de ouk oidamen</em>); here it marks the one about whom the truthful witness spoke.</p>',

    "42": '<p><strong>καὶ ἐπίστευσαν πολλοὶ ἐκεῖ εἰς αὐτόν</strong> — "and many believed in him there." <em>Episteusan</em> (aorist — a decisive moment of faith). The contrast with Jerusalem is complete: where the Temple establishment attempts to stone and arrest Jesus, this mixed crowd in Transjordan (beyond the Jordan, where Gentile territory begins) believes. The first Jewish community of disciples formed around John\'s baptizing site; now that same ground produces faith in the one John pointed to. The Evangelist closes the unit with the simplest possible notation: many believed there.</p>'
  }
}


def main():
    existing = load_comm('mkt-original', 'john')
    merge_comm(existing, JOHN)
    save_comm('mkt-original', 'john', existing)
    print('John 9–10 mkt-original written.')

if __name__ == '__main__':
    main()
